  for (edge <- edges) {
    val u = edge(0)
    val v = edge(1)
    val w = edge(2)
    if (!graph.contains(u)) graph(u) = Array()
    if (!graph.contains(v)) graph(v) = Array()
    graph(u) = graph(u) :+ (v, w)
    graph(v) = graph(v) :+ (u, w)
  }

